import React, { useEffect } from 'react';
import { Button, Slideout } from '@linm-soft-org/linm-web-common-components';
import { documentTypeLabel } from '../../utils/reportDocumentDrillDown';
import { ReportDocumentFormEmbed } from './ReportDocumentFormEmbed';
import styles from './ReportSourceDocumentSlideout.module.css';

export type ReportSourceDocumentSlideoutProps = {
  isOpen: boolean;
  onClose: () => void;
  documentType: string | null;
  documentId: string | null;
  voucherCode?: string;
  title: string;
  closeLabel: string;
  openFullLabel: string;
  loadErrorLabel: string;
  onOpenFullPage: () => void;
  testIdPrefix: string;
};

export const ReportSourceDocumentSlideout: React.FC<ReportSourceDocumentSlideoutProps> = ({
  isOpen,
  onClose,
  documentType,
  documentId,
  voucherCode,
  title,
  closeLabel,
  openFullLabel,
  onOpenFullPage,
  testIdPrefix,
}) => {
  const slideoutTitle = voucherCode
    ? `${title}: ${voucherCode}`
    : documentType
      ? `${title}: ${documentTypeLabel(documentType)}`
      : title;

  const footer = (
    <div className={styles.footerBar}>
      <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-slideout-close`}>
        {closeLabel}
      </Button>
      <Button
        variant="primary"
        onClick={onOpenFullPage}
        disabled={!documentType || !documentId}
        data-testid={`${testIdPrefix}-slideout-open-full`}
      >
        {openFullLabel}
      </Button>
    </div>
  );

  return (
    <Slideout
      isOpen={isOpen}
      onClose={onClose}
      title={slideoutTitle}
      width="min(960px, 92vw)"
      customFooter={footer}
      data-testid={`${testIdPrefix}-document-slideout`}
    >
      {isOpen && documentType && documentId ? (
        <ReportDocumentFormEmbed
          documentType={documentType}
          documentId={documentId}
          testIdPrefix={testIdPrefix}
        />
      ) : null}
    </Slideout>
  );
};
