import type { LedgerEntryDto } from '../../services/kt/models';

/** BE `LedgerRowTags` — CP_GLSO1 Ftag parity. */
export const LEDGER_ROW_TAGS = {
  detail: 0,
  opening: 1,
  periodTotal: 2,
} as const;

export function isLedgerSyntheticRow(row: LedgerEntryDto): boolean {
  const tag = row.rowTag ?? LEDGER_ROW_TAGS.detail;
  return tag === LEDGER_ROW_TAGS.opening || tag === LEDGER_ROW_TAGS.periodTotal;
}

/** STT for detail rows only — synthetic rows return null (display «—»). */
export function ledgerDetailRowNo(
  items: LedgerEntryDto[],
  index: number,
  page: number,
  pageSize: number,
): number | null {
  const row = items[index];
  if (isLedgerSyntheticRow(row)) return null;
  const detailsBeforeOnPage = items
    .slice(0, index)
    .filter(r => !isLedgerSyntheticRow(r)).length;
  if (pageSize <= 0) return detailsBeforeOnPage + 1;
  return (page - 1) * pageSize + detailsBeforeOnPage + 1;
}
