import React, { useCallback, useMemo, useState } from 'react';
import { useViewMobileLayout } from '@linm-soft-org/linm-web-common-components';
import type { ReceivablePayableDto } from '../../services/kt/models';
import { formatVnd } from '../../utils/formatters';
import {
  getReportGridRowMenuHintMessage,
  isRowEditHintDismissed,
  reportGridRowHintDismissStorageKey,
} from '../../utils/reportGridRowMenuHint';
import {
  isReportGridMenuClickTrigger,
  isReportGridMenuContextMenuTrigger,
} from './reportGridMenuTrigger';
import { ReportGridRowHintLayer } from './ReportGridRowHintLayer';
import { useReportGridRowLongPress } from './useReportGridRowLongPress';
import { ReportRowActionMenu, type ReportRowMenuAction } from './ReportRowActionMenu';
import erp from '../../styles/erpPage.module.css';
import rowStyles from './LedgerReportGrid.module.css';

export type CongNoReportGridLabels = {
  colNo: string;
  colCustomer: string;
  colType: string;
  colTotalDebit: string;
  colTotalCredit: string;
  colBalance: string;
  rowMenuRefreshData: string;
  rowMenuPrint: string;
  rowMenuExport: string;
  rowMenuChart: string;
  rowMenuHint: string;
  rowMenuHintTouch: string;
};

export type CongNoReportGridProps = {
  rows: ReceivablePayableDto[];
  rowNo: (index: number) => number;
  labels: CongNoReportGridLabels;
  testIdPrefix: string;
  onRefresh: () => void;
  onPrint?: () => void;
  onChart?: () => void;
  canChart?: boolean;
};

export function CongNoReportGrid({
  rows,
  rowNo,
  labels,
  testIdPrefix,
  onRefresh,
  onPrint,
  onChart,
  canChart = false,
}: CongNoReportGridProps): React.ReactElement {
  const viewMobile = useViewMobileLayout();
  const hintDismissStorageKey = reportGridRowHintDismissStorageKey(testIdPrefix);
  const getRowMenuHintMessage = useMemo(
    () => getReportGridRowMenuHintMessage(viewMobile ? labels.rowMenuHintTouch : labels.rowMenuHint),
    [viewMobile, labels.rowMenuHint, labels.rowMenuHintTouch],
  );

  const [menu, setMenu] = useState<{ x: number; y: number; row: ReceivablePayableDto } | null>(null);
  const [rowMenuHint, setRowMenuHint] = useState<{ x: number; y: number; message: string } | null>(null);

  const rowMenuLabels = useMemo(
    () => ({
      viewDocument: '',
      viewReportDetail: '',
      refreshData: labels.rowMenuRefreshData,
      print: labels.rowMenuPrint,
      export: labels.rowMenuExport,
      chart: labels.rowMenuChart,
    }),
    [labels],
  );

  const openRowMenu = useCallback((x: number, y: number, row: ReceivablePayableDto) => {
    setRowMenuHint(null);
    setMenu({ x, y, row });
  }, []);

  const longPress = useReportGridRowLongPress<ReceivablePayableDto>({
    enabled: true,
    onLongPress: ({ row, x, y }) => openRowMenu(x, y, row),
  });

  const handleRowMenuSelect = useCallback(
    (action: ReportRowMenuAction) => {
      switch (action) {
        case 'refreshData':
          onRefresh();
          break;
        case 'print':
          onPrint?.();
          break;
        case 'chart':
          onChart?.();
          break;
        default:
          break;
      }
    },
    [onRefresh, onPrint, onChart],
  );

  const handleRowClick = useCallback(
    (e: React.MouseEvent, row: ReceivablePayableDto) => {
      if (longPress.consumeClickAfterLongPress()) return;
      if (isReportGridMenuClickTrigger(e)) {
        e.preventDefault();
        e.stopPropagation();
        openRowMenu(e.clientX, e.clientY, row);
        return;
      }
      const hintMessage = getRowMenuHintMessage(row as never);
      if (hintMessage && !isRowEditHintDismissed(hintDismissStorageKey)) {
        setRowMenuHint({ x: e.clientX, y: e.clientY, message: hintMessage });
      } else {
        setRowMenuHint(null);
      }
    },
    [longPress, openRowMenu, getRowMenuHintMessage, hintDismissStorageKey],
  );

  const handleRowDoubleClick = useCallback(
    (e: React.MouseEvent, row: ReceivablePayableDto) => {
      openRowMenu(e.clientX, e.clientY, row);
    },
    [openRowMenu],
  );

  const handleRowContextMenu = useCallback(
    (e: React.MouseEvent, row: ReceivablePayableDto) => {
      if (!isReportGridMenuContextMenuTrigger(e)) return;
      e.preventDefault();
      e.stopPropagation();
      openRowMenu(e.clientX, e.clientY, row);
    },
    [openRowMenu],
  );

  return (
    <>
      <div className={erp.tableWrapper}>
        <table className={erp.table}>
          <thead>
            <tr>
              <th className={erp.colNo}>{labels.colNo}</th>
              <th>{labels.colCustomer}</th>
              <th>{labels.colType}</th>
              <th className={erp.colRight}>{labels.colTotalDebit}</th>
              <th className={erp.colRight}>{labels.colTotalCredit}</th>
              <th className={erp.colRight}>{labels.colBalance}</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((r, i) => (
              <tr
                key={r.customerId}
                className={rowStyles.row}
                data-testid={`${testIdPrefix}-row-${i}`}
                onClick={e => handleRowClick(e, r)}
                onDoubleClick={e => handleRowDoubleClick(e, r)}
                onContextMenu={e => handleRowContextMenu(e, r)}
                onPointerDown={e => longPress.onPointerDown(e, r)}
                onPointerMove={longPress.onPointerMove}
                onPointerUp={longPress.onPointerUp}
                onPointerCancel={longPress.onPointerCancel}
              >
                <td className={erp.colNo}>{rowNo(i)}</td>
                <td>{r.customerName}</td>
                <td>{r.customerType}</td>
                <td className={erp.colRight}>{formatVnd(r.totalDebit)}</td>
                <td className={erp.colRight}>{formatVnd(r.totalCredit)}</td>
                <td className={erp.colRight}>{formatVnd(r.balance)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <ReportGridRowHintLayer
        hint={rowMenuHint}
        onDismiss={() => setRowMenuHint(null)}
        dismissStorageKey={hintDismissStorageKey}
      />
      <ReportRowActionMenu
        open={menu != null}
        x={menu?.x ?? 0}
        y={menu?.y ?? 0}
        onClose={() => setMenu(null)}
        onSelect={handleRowMenuSelect}
        labels={rowMenuLabels}
        canOpenDocument={false}
        canViewReportDetail={false}
        canChart={canChart}
        testIdPrefix={testIdPrefix}
      />
    </>
  );
}
